import assert from "node:assert/strict";
import { reducer } from "../src/domain/reducer.js";
import { initialState } from "../src/domain/state.js";
import type { GameState, Key } from "../src/domain/types.js";

const press = (state: GameState, key: Key): GameState => reducer(state, { type: "PRESS_KEY", key });

export const runReducerUnlockTests = (): void => {
  let state = initialState();

  state = press(state, "=");
  state = press(state, "=");
  assert.equal(state.unlocks.utilities.CE, false, "CE should still be locked at roll length 2");

  state = press(state, "=");
  assert.equal(state.calculator.roll.length, 3, "roll length should be 3");
  assert.equal(state.unlocks.utilities.CE, true, "CE unlocks at roll length 3");
  assert.ok(state.completedUnlockIds.includes("unlock-ce-on-roll-3"), "unlock id should be recorded");

  state = initialState();
  state = press(state, "1");
  state = press(state, "+");
  state = press(state, "2");
  state = press(state, "=");
  assert.equal(state.calculator.total, 3n, "single-slot plus updates total");
  assert.equal(state.calculator.roll.at(-1), 3n, "single-slot plus appends to roll");
  assert.equal(state.calculator.operationSlots.length, 1, "slot remains configured");

  state = initialState();
  state = press(state, "=");
  state = press(state, "=");
  state = press(state, "=");
  state = press(state, "+");
  state = press(state, "5");
  state = press(state, "CE");
  assert.equal(state.calculator.total, 0n, "digit in drafting slot should not alter total");
  assert.equal(state.calculator.roll.length, 0, "CE clears roll");
  assert.equal(state.calculator.operationSlots.length, 0, "CE clears operation slots");
  assert.equal(state.calculator.draftingSlot, null, "CE clears draft slot");

  state = initialState();
  state = press(state, "1");
  state = press(state, "+");
  state = press(state, "2");
  state = press(state, "=");
  assert.equal(state.calculator.total, 3n, "setup total after first execution");
  assert.equal(state.calculator.roll.length, 1, "setup roll is active");
  assert.equal(state.calculator.operationSlots.length, 1, "setup slot exists");
  state = press(state, "+");
  assert.equal(state.calculator.operationSlots.length, 0, "operator on active roll first applies CE and clears slots");
  assert.deepEqual(
    state.calculator.draftingSlot,
    { operator: "+", operandInput: "" },
    "operator on active roll starts fresh drafting slot",
  );
  assert.equal(state.calculator.total, 3n, "operator on active roll keeps total");
  assert.deepEqual(state.calculator.roll, [], "operator on active roll clears roll via CE behavior");

  state = initialState();
  state = press(state, "1");
  state = press(state, "=");
  assert.equal(state.calculator.roll.length, 1, "setup roll active for digit behavior");
  state = press(state, "7");
  assert.equal(state.calculator.total, 7n, "digit on active roll first applies C then enters digit");
  assert.equal(state.calculator.roll.length, 0, "digit on active roll clears roll");
  assert.equal(state.calculator.operationSlots.length, 0, "digit on active roll clears operation slots");
  assert.equal(state.calculator.draftingSlot, null, "digit on active roll clears drafting slot");

  state = initialState();
  state = press(state, "C");
  state = press(state, "1");
  state = press(state, "+");
  state = press(state, "2");
  state = press(state, "=");
  state = press(state, "+");
  state = press(state, "4");
  assert.equal(state.calculator.total, 3n, "digit while drafting a slot should not clear total");
  assert.deepEqual(state.calculator.roll, [], "operator before drafting clears roll via CE behavior");
  assert.deepEqual(
    state.calculator.draftingSlot,
    { operator: "+", operandInput: "4" },
    "digit while drafting a slot should populate operand input",
  );
};
